/*
 * log() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly log     (test_log_opt.elf)
 *   2. Linked with toolchain's default log          (test_log_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifdef EN_PERF
static volatile double g_acc;

static void emit(double x)
{
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += log(vx);
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}
#else
static void emit(double x)
{
    double r = log(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}
#endif

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (8) --- */
    emit(0.0);                                     /* log(0) = -Inf */
    emit(-0.0);                                    /* log(-0) = -Inf */
    emit_u(0x7ff8000000000000ULL);                 /* qNaN */
    emit_u(0x7ff0000000000001ULL);                 /* sNaN */
    emit_u(0xfff8000000000000ULL);                 /* -qNaN */
    emit_u(0x7ff0000000000000ULL);                 /* +Inf: log(Inf) = Inf */
    emit_u(0xfff0000000000000ULL);                 /* -Inf: log(-Inf) = NaN */
    emit_u(0xbff0000000000000ULL);                 /* -1.0: domain error -> NaN */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    /* Valid inputs; log produces very large negative results */
    emit_u(0x0000000000000001ULL);                 /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);                 /* min negative subnormal: domain error */
    emit_u(0x0008000000000000ULL);                 /* mid subnormal */
    emit_u(0x8008000000000000ULL);                 /* -mid subnormal: domain error */
    emit_u(0x000fffffffffffffULL);                 /* max subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);                 /* -max subnormal: domain error */

    /* --- Section 3: Normal boundary values (4) --- */
    emit(DBL_MIN);                                 /* 2^-1022: smallest normal */
    emit(-DBL_MIN);                                /* negative: domain error -> NaN */
    emit_u(0x0010000000000001ULL);                 /* one ULP above DBL_MIN */
    emit(DBL_MAX);                                 /* 0x7fefffffffffffff: largest normal */

    /* --- Section 4: ULP neighbors of 1.0 (10) --- */
    /* log(1.0) = 0 exactly; critical precision zone */
    emit_u(0x3fefffffffffffffULL);                 /* one ULP below 1.0 */
    emit(1.0);                                     /* log(1) = 0 exactly */
    emit_u(0x3ff0000000000001ULL);                 /* one ULP above 1.0 */
    emit_u(0x3feffffffffffffeULL);                 /* two ULPs below 1.0 */
    emit_u(0x3ff0000000000002ULL);                 /* two ULPs above 1.0 */
    emit_u(0x3fefffffffffffc0ULL);                 /* several ULPs below 1.0 */
    emit_u(0x3ff0000000000040ULL);                 /* several ULPs above 1.0 */
    emit_u(0x3feffffffffffb00ULL);                 /* ~2^-10 below 1.0 */
    emit_u(0x3ff0000000000500ULL);                 /* ~2^-10 above 1.0 */
    emit_u(0x3feffffffffffff0ULL);                 /* 16 ULPs below 1.0 */

    /* --- Section 5: Mathematical constants (12) --- */
    emit(2.718281828459045);                       /* e: log(e) = 1 */
    emit(2.0);                                     /* log(2) = ln2 */
    emit(0.5);                                     /* log(0.5) = -ln2 */
    emit(10.0);                                    /* log(10) = ln10 */
    emit(0.1);                                     /* log(0.1) = -ln10 */
    emit_u(0x3fe62e42fefa39efULL);                 /* ln2 ~ 0.6931: log(ln2) */
    emit_u(0x4000000000000000ULL);                 /* 2.0 exact bit pattern */
    emit(4.0);                                     /* log(4) = 2*ln2 */
    emit(0.25);                                    /* log(0.25) = -2*ln2 */
    emit(7.38905609893065);                        /* e^2: log(e^2) = 2 */
    emit(1.0 / 2.718281828459045);                 /* 1/e: log(1/e) = -1 */
    emit(2.302585092994046);                       /* ln10: log(ln10) */

    /* --- Section 6: Powers of 2 (14) --- */
    /* log(2^n) = n*ln2; exercises exponent extraction */
    emit_u(0x4010000000000000ULL);                 /* 4.0 = 2^2 */
    emit_u(0x4020000000000000ULL);                 /* 8.0 = 2^3 */
    emit_u(0x4030000000000000ULL);                 /* 16.0 = 2^4 */
    emit_u(0x4060000000000000ULL);                 /* 128.0 = 2^7 */
    emit_u(0x4090000000000000ULL);                 /* 1024.0 = 2^10 */
    emit_u(0x40f0000000000000ULL);                 /* 32768.0 = 2^15 */
    emit_u(0x4330000000000000ULL);                 /* 2^52: mantissa precision boundary */
    emit_u(0x7fe0000000000000ULL);                 /* 2^1023: near DBL_MAX */
    emit_u(0x3fe0000000000000ULL);                 /* 0.5 = 2^-1 exact */
    emit_u(0x3fd0000000000000ULL);                 /* 0.25 = 2^-2 exact */
    emit_u(0x3fb0000000000000ULL);                 /* 2^-4 = 0.0625 */
    emit_u(0x3f50000000000000ULL);                 /* 2^-10 */
    emit_u(0x3c00000000000000ULL);                 /* 2^-63 */
    emit_u(0x0020000000000000ULL);                 /* 2^-1021: near DBL_MIN */

    /* --- Section 7: Near-zero inputs (8) --- */
    /* log(x) is large negative; exercises underflow/denormal result path */
    emit(1.0e-10);
    emit(1.0e-20);
    emit(1.0e-50);
    emit(1.0e-100);
    emit(1.0e-150);
    emit(1.0e-200);
    emit(1.0e-300);
    emit_u(0x0010000000000000ULL);                 /* DBL_MIN = 2^-1022 */

    /* --- Section 8: Large values (8) --- */
    /* log(x) grows slowly; tests large-exponent path */
    emit(1.0e10);
    emit(1.0e50);
    emit(1.0e100);
    emit(1.0e150);
    emit(1.0e200);
    emit(1.0e250);
    emit(1.0e300);
    emit_u(0x7fefffffffffffffULL);                 /* DBL_MAX */

    /* --- Section 9: Negative inputs / domain errors (10) --- */
    /* All return NaN; exercises error-handling path */
    emit(-1.0);
    emit(-2.0);
    emit(-0.5);
    emit(-10.0);
    emit(-1.0e-10);
    emit(-1.0e10);
    emit(-1.0e100);
    emit_u(0xc000000000000000ULL);                 /* -2.0 exact */
    emit_u(0xbfe0000000000000ULL);                 /* -0.5 exact */
    emit_u(0xc024000000000000ULL);                 /* -10.0 exact */

    /* --- Section 10: Near-1.0 arithmetic offsets (20) --- */
    /* Exercises the log(1+x) ~ x Taylor series path for |x| << 1 */
    emit(1.0 + 1.0e-4);
    emit(1.0 - 1.0e-4);
    emit(1.0 + 1.0e-6);
    emit(1.0 - 1.0e-6);
    emit(1.0 + 1.0e-8);
    emit(1.0 - 1.0e-8);
    emit(1.0 + 1.0e-10);
    emit(1.0 - 1.0e-10);
    emit(1.0 + 1.0e-12);
    emit(1.0 - 1.0e-12);
    emit(1.0 + 1.0e-14);
    emit(1.0 - 1.0e-14);
    emit(1.0 + 1.0e-15);
    emit(1.0 - 1.0e-15);
    emit(1.0 + 0.001);
    emit(1.0 - 0.001);
    emit(1.0 + 0.01);
    emit(1.0 - 0.01);
    emit(1.0 + 0.1);
    emit(1.0 - 0.1);
}

/* ------------------------------------------------------------------ */

/* Sweep [0.1, 10.0] in 200 steps each direction */
#ifndef EN_PERF
static void test_sweep(void)
{
    double lo = 0.1;
    double hi = 10.0;
    int nsteps = 200;
    double step = (hi - lo) / (double)nsteps;

    /* [0.1, 10.0] */
    for (int i = 0; i <= nsteps; i++)
        emit(lo + (double)i * step);

    /* [10.0, 0.1] (decreasing) */
    for (int i = 0; i <= nsteps; i++)
        emit(hi - (double)i * step);
}

/* Sample near 1.0: [0.99999, 1.00001] every 2^45 ULP */
static void test_exhaustive_small(void)
{
    uint64_t center = 0x3ff0000000000000ULL; /* 1.0 */
    uint64_t radius = (1ULL << 18); /* ~131k ULP from 1.0 */
    uint64_t step = 1ULL << 45;

    for (uint64_t b = center - radius; b <= center + radius; b += step)
        emit_u(b);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf g_acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

